// Rise 6.0 - AntiResourcePack module:
// When server sends S48PacketResourcePackSend:
if (event.getPacket() instanceof S48PacketResourcePackSend) {
    S48PacketResourcePackSend s48 = (S48PacketResourcePackSend) event.getPacket();
    String hash = s48.getHash();

    // Cancel the vanilla resource pack prompt
    event.setCancelled(true);

    // Send ACCEPTED immediately
    mc.thePlayer.sendQueue.addToSendQueue(
        new C19PacketResourcePackStatus(hash, C19PacketResourcePackStatus.EnumStatus.ACCEPTED));

    // After short delay, send SUCCESSFULLY_LOADED
    new Thread(() -> {
        try { Thread.sleep(1000); } catch (InterruptedException e) {}
        mc.thePlayer.sendQueue.addToSendQueue(
            new C19PacketResourcePackStatus(hash, C19PacketResourcePackStatus.EnumStatus.SUCCESSFULLY_LOADED));
    }).start();
}

