package net.minecraft.network.play.client;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import java.io.IOException;

public class C19PacketResourcePackStatus implements Packet<INetHandlerPlayServer> {
    private String hash;
    private EnumStatus status;

    public enum EnumStatus {
        SUCCESSFULLY_LOADED,
        DECLINED,
        FAILED_DOWNLOAD,
        ACCEPTED
    }

    public C19PacketResourcePackStatus() {}
    public C19PacketResourcePackStatus(String hashIn, EnumStatus statusIn) {
        this.hash = hashIn;
        this.status = statusIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.hash = buf.readStringFromBuffer(40);
        this.status = buf.readEnumValue(EnumStatus.class);
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeString(this.hash);
        buf.writeEnumValue(this.status);
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processResourcePackStatus(this);
    }

    public String getHash() { return this.hash; }
    public EnumStatus getStatus() { return this.status; }
}
